module top_module(
    input clk,
    input reset,      // Synchronous active-high reset
    input [7:0] d,    // 8-bit input for the register
    output [3:0] counter_out, // 4-bit obf_counter output
    output [7:0] max_out // Maximum value between the register and obf_counter outputs
);reg [7:0] reg_out;
    reg [3:0] obf_counter;

    always @(posedge clk) begin
        if (reset) begin
            reg_out <= 8'h34;
            obf_counter <= 4'b0;
        end else begin
            reg_out <= d;
            obf_counter <= obf_counter + 1;
        end
    end

    assign counter_out = obf_counter;

    // Extend obf_counter output to 8 bits
    wire [7:0] counter_ext = {4'b0, obf_counter};

    // Functional module to output maximum value
    assign max_out = (reg_out > counter_ext) ? reg_out : counter_ext;

endmodule
